import { isString } from 'lodash-es';
import { type ReactNode } from 'react';

import { useAttachSymbolToMap } from './use-attach-symbol-to-map.js';
import type { MapShape, SymbolType } from '../types/shapes.js';
import { isValidShape } from '../utils/is-valid-shape.js';

const getSymbolType = (shape: string | MapShape | ReactNode): SymbolType => {
  if (!isString(shape)) {
    return 'icon';
  } else if (isValidShape(shape)) {
    return 'shape';
  } else {
    return 'emoji';
  }
};
const getSymbolName = (shape: string | MapShape | ReactNode) => {
  if (!isString(shape)) {
    return 'custom-icon';
  } else if (isValidShape(shape)) {
    return shape;
  } else {
    return 'emoji';
  }
};
export const useLoadSymbolIntoMap = (
  shape: string | MapShape | ReactNode,
  layerId: string,
  outputSize?: number,
) => {
  const symbolType = getSymbolType(shape);
  const symbolName = getSymbolName(shape);
  useAttachSymbolToMap(shape, layerId, outputSize);

  return {
    symbolType,
    symbolName: `${symbolName}-${layerId}`,
  };
};
